if (! function_exists('array_set_operations')) {
    function array_set_operations($a, $operation, $b = null)
    {
        if (!is_array($a)) {
            return json_encode(['error' => 'a must be an array']);
        }
        
        $setA = array_values(array_unique($a));
        $setB = isset($b) ? array_values(array_unique($b)) : [];

        // Validate b is provided for operations that need it
        $needsB = ['union', 'intersect', 'diff', 'symdiff'];
        if (in_array($operation, $needsB) && !isset($b)) {
            return json_encode(['error' => "Operation '$operation' requires array b"]);
        }

        switch ($operation) {
            case 'union':
                $result = array_values(array_unique(array_merge($setA, $setB)));
                return json_encode(['operation' => 'union', 'count' => count($result), 'items' => $result]);
            
            case 'intersect':
                $result = array_values(array_intersect($setA, $setB));
                return json_encode(['operation' => 'intersect', 'count' => count($result), 'items' => $result]);
            
            case 'diff':
                $result = array_values(array_diff($setA, $setB));
                return json_encode(['operation' => 'diff', 'count' => count($result), 'items' => $result]);
            
            case 'symdiff':
                $inAonly = array_diff($setA, $setB);
                $inBonly = array_diff($setB, $setA);
                $result = array_values(array_merge($inAonly, $inBonly));
                return json_encode(['operation' => 'symdiff', 'count' => count($result), 'items' => $result]);
            
            case 'unique':
                $result = array_values(array_unique($a));
                return json_encode(['operation' => 'unique', 'count' => count($result), 'items' => $result]);
            
            default:
                return json_encode(['error' => "Unknown operation: $operation"]);
        }
    }
